PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE Meta (id INTEGER PRIMARY KEY AUTOINCREMENT, key TEXT UNIQUE NOT NULL, value TEXT NOT NULL);
INSERT INTO Meta VALUES(1,'revision','5');
CREATE TABLE Subscriber (id INTEGER PRIMARY KEY AUTOINCREMENT, created TIMESTAMP NOT NULL, updated TIMESTAMP NOT NULL, imsi NUMERIC UNIQUE NOT NULL, name TEXT, extension TEXT UNIQUE, authorized INTEGER NOT NULL DEFAULT 0, tmsi TEXT UNIQUE, lac INTEGER NOT NULL DEFAULT 0, expire_lu TIMESTAMP DEFAULT NULL);
CREATE TABLE AuthToken (id INTEGER PRIMARY KEY AUTOINCREMENT, subscriber_id INTEGER UNIQUE NOT NULL, created TIMESTAMP NOT NULL, token TEXT UNIQUE NOT NULL);
CREATE TABLE Equipment (id INTEGER PRIMARY KEY AUTOINCREMENT, created TIMESTAMP NOT NULL, updated TIMESTAMP NOT NULL, name TEXT, classmark1 NUMERIC, classmark2 BLOB, classmark3 BLOB, imei NUMERIC UNIQUE NOT NULL);
CREATE TABLE EquipmentWatch (id INTEGER PRIMARY KEY AUTOINCREMENT, created TIMESTAMP NOT NULL, updated TIMESTAMP NOT NULL, subscriber_id NUMERIC NOT NULL, equipment_id NUMERIC NOT NULL, UNIQUE (subscriber_id, equipment_id) );
CREATE TABLE SMS (id INTEGER PRIMARY KEY AUTOINCREMENT, created TIMESTAMP NOT NULL, sent TIMESTAMP, deliver_attempts INTEGER NOT NULL DEFAULT 0, valid_until TIMESTAMP, reply_path_req INTEGER NOT NULL, status_rep_req INTEGER NOT NULL, is_report INTEGER NOT NULL, msg_ref INTEGER NOT NULL, protocol_id INTEGER NOT NULL, data_coding_scheme INTEGER NOT NULL, ud_hdr_ind INTEGER NOT NULL, src_addr TEXT NOT NULL, src_ton INTEGER NOT NULL, src_npi INTEGER NOT NULL, dest_addr TEXT NOT NULL, dest_ton INTEGER NOT NULL, dest_npi INTEGER NOT NULL, user_data BLOB, header BLOB, text TEXT );
CREATE TABLE VLR (id INTEGER PRIMARY KEY AUTOINCREMENT, created TIMESTAMP NOT NULL, updated TIMESTAMP NOT NULL, subscriber_id NUMERIC UNIQUE NOT NULL, last_bts NUMERIC NOT NULL );
CREATE TABLE ApduBlobs (id INTEGER PRIMARY KEY AUTOINCREMENT, created TIMESTAMP NOT NULL, apdu_id_flags INTEGER NOT NULL, subscriber_id INTEGER NOT NULL, apdu BLOB );
CREATE TABLE Counters (id INTEGER PRIMARY KEY AUTOINCREMENT, timestamp TIMESTAMP NOT NULL, value INTEGER NOT NULL, name TEXT NOT NULL );
CREATE TABLE RateCounters (id INTEGER PRIMARY KEY AUTOINCREMENT, timestamp TIMESTAMP NOT NULL, value INTEGER NOT NULL, name TEXT NOT NULL, idx INTEGER NOT NULL );
CREATE TABLE AuthKeys (subscriber_id INTEGER PRIMARY KEY, algorithm_id INTEGER NOT NULL, a3a8_ki BLOB );
CREATE TABLE AuthLastTuples (subscriber_id INTEGER PRIMARY KEY, issued TIMESTAMP NOT NULL, use_count INTEGER NOT NULL DEFAULT 0, key_seq INTEGER NOT NULL, rand BLOB NOT NULL, sres BLOB NOT NULL, kc BLOB NOT NULL );
